function compoundInterest(
  principal: number,
  rate: number,
  years: number
): number {
  return principal * Math.pow(1 + rate, years);
}

const result = compoundInterest(10000, 0.07, 10);
console.log(`$10,000 at 7% for 10 years: $${result.toFixed(2)}`);

