function paginate(
  total: number,
  page: number = 1,
  perPage: number = 20
): { start: number; end: number; totalPages: number } {
  const totalPages = Math.ceil(total / perPage);
  const start = (page - 1) * perPage + 1;
  const end = Math.min(page * perPage, total);
  return { start, end, totalPages };
}

const p1 = paginate(147);
