function stats(...values: number[]): {
  count: number;
  sum: number;
  min: number;
  max: number;
  avg: number;
} {
  const count = values.length;
  const sum = values.reduce((a, b) => a + b, 0);
  return {
    count,
    sum,
    min: Math.min(...values),
    max: Math.max(...values),
    avg: Math.round(sum / count),
  };
}

