console.log(`Range: ${result.min}–${result.max}`);
console.log(`Average: ${result.avg}`);

type TextTransformer = (text: string) => string;

const trim: TextTransformer       = s => s.trim();
const lowercase: TextTransformer  = s => s.toLowerCase();
const removeSpaces: TextTransformer = s => s.replace(/\s+/g, "-");
const addPrefix = (prefix: string): TextTransformer => s => `${prefix}-${s}`;

function pipeline(text: string, ...transformers: TextTransformer[]): string {
  return transformers.reduce((s, fn) => fn(s), text);
}

const raw = "  TypeScript Tutorial  ";
const slug = pipeline(raw, trim, lowercase, removeSpaces, addPrefix("ts"));
console.log(slug);

type EventHandler = (event: string, payload?: unknown) => void;

const handlers: EventHandler[] = [];

function on(handler: EventHandler): void {
  handlers.push(handler);
}

function emit(event: string, payload?: unknown): void {
  for (const handler of handlers) {
    handler(event, payload);
  }
}

on((event, payload) => {
  console.log(`Event: ${event}`);
  if (payload) console.log(`Payload: ${JSON.stringify(payload)}`);
});

emit("user.login", { userId: 42, timestamp: "2024-01-15" });
emit("page.view");

function format(value: number): string;
function format(value: Date): string;
function format(value: boolean): string;
function format(value: number | Date | boolean): string {
  if (typeof value === "number") {
    return `$${value.toFixed(2)}`;
  } else if (value instanceof Date) {
    return value.toISOString().slice(0, 10);
  } else {
    return value ? "Yes" : "No";
  }
}

