console.log(format(true));
console.log(format(false));

function rateLimit<T extends unknown[]>(
  fn: (...args: T) => void,
  limitMs: number
): (...args: T) => void {
  let lastCall = 0;
  return (...args: T) => {
    const now = Date.now();
    if (now - lastCall >= limitMs) {
      lastCall = now;
      fn(...args);
    } else {
      console.log(`Rate limited — wait ${limitMs}ms between calls`);
    }
  };
}

function sendAlert(message: string): void {
