const double    = (n: number): number => n * 2;
const addOne    = (n: number): number => n + 1;
const square    = (n: number): number => n * n;
const toString  = (n: number): string => `Result: ${n}`;

// Compose number transformers
function compose<A, B, C, D>(
  f: (a: A) => B,
  g: (b: B) => C,
  h: (c: C) => D
): (a: A) => D {
  return (a) => h(g(f(a)));
}

const transform = compose(double, addOne, square);

for (const n of [1, 2, 3, 4, 5]) {
  console.log(`${n} → double → +1 → square = ${transform(n)}`);
}

async function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function fetchPrice(product: string): Promise<number> {
  await delay(0); // simulate async
  const prices: Record<string, number> = {
    "starter":    19,
    "pro":        49,
    "enterprise": 199,
  };
  return prices[product] ?? 0;
}

async function main(): Promise<void> {
  const plans = ["starter", "pro", "enterprise"];
  for (const plan of plans) {
    const price = await fetchPrice(plan); // price is number, not Promise<number>
    console.log(`${plan}: $${price}/mo`);
  }
}

main();

type Shape =
  | { kind: "circle";    radius: number }
  | { kind: "square";    side: number }
  | { kind: "rectangle"; width: number; height: number };

function assertNever(x: never): never {
  throw new Error(`Unhandled case: ${JSON.stringify(x)}`);
}

function describe(shape: Shape): string {
  switch (shape.kind) {
    case "circle":    return `Circle with radius ${shape.radius}`;
    case "square":    return `Square with side ${shape.side}`;
    case "rectangle": return `Rectangle ${shape.width}×${shape.height}`;
    default:          return assertNever(shape); // compile error if a case is missing
  }
}

const shapes: Shape[] = [
  { kind: "circle",    radius: 5 },
  { kind: "square",    side: 4 },
  { kind: "rectangle", width: 6, height: 3 },
];

for (const s of shapes) {
  console.log(describe(s));
}
